import React, { useState } from 'react';
import { View, Button, Text, Alert } from 'react-native';
import * as AuthSession from 'expo-auth-session';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';
const redirectUri = AuthSession.makeRedirectUri({ useProxy: true });
const authorizationEndpoint = 'https://example.com/oauth/authorize';
const tokenEndpoint = 'https://example.com/oauth/token';

export default function App() {
  const [token, setToken] = useState(null);

  const handleOAuthLogin = async () => {
    try {
      const authUrl = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}`;
      const result = await AuthSession.startAsync({ authUrl });

      if (result.type === 'success' && result.params.code) {
        const response = await fetch(tokenEndpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/x-www-form-urlencoded',
          },
          body: `grant_type=authorization_code&code=${result.params.code}&redirect_uri=${encodeURIComponent(redirectUri)}&client_id=${clientId}&client_secret=${clientSecret}`,
        });

        const data = await response.json();
        if (data.access_token) {
          setToken(data.access_token);
          Alert.alert('Success', 'Logged in successfully');
        } else {
          Alert.alert('Error', 'Failed to retrieve access token');
        }
      } else {
        Alert.alert('Error', 'Authorization failed');
      }
    } catch (error) {
      Alert.alert('Error', 'An error occurred during authentication');
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Button title="Login with OAuth" onPress={handleOAuthLogin} />
      {token && <Text>Access Token: {token}</Text>}
    </View>
  );
}